\label{res:consistency_KQD_p}
    Let $\calX \subseteq  R^d$, $
u$ have a density, $ P,  Q$ be measures on $\calX$ with densities bounded away from zero, $f_ P(x) \geq c_ P>0$ and $f_ Q(x) \geq c_ Q>0$. Suppose $ E_{X \sim  P} [k(X, X)^{
icefrac{p}{2}}]<\infty$ and $ E_{Y \sim  Q} [ k(Y, Y)^{
icefrac{p}{2}}]<\infty$, and $x_1, \dots, x_N \sim  P, y_1, \dots, y_N \sim  Q$. Then,

     egin{align*}
         E_{\substack{x_1, \dots, x_N \sim  P \ y_1, \dots, y_N \sim  Q}}| \ekqd_p( P_N,  Q_N;
u, \gamma_L) - \ekqd_p( P,  Q;
u, \gamma) | = igo(L^{-
icefrac{1}{2}} + N^{-
icefrac{1}{2}}).
    \end{align*}

\label{conj2:generalSGD}
  For any $h \in \operatorname{Lip}_1(\mathbb{R})$, the Stein equation
  \begin{equation}\label{generalSGD}
    h(y) - \mathbb{E}[h(Z)] = -y^h g_h'(y) + \mathbb{E}[\xi_k^{2}] g_h''(y)
  \end{equation}
  admits a solution $g_h:\mathbb{R}\to\mathbb{R}$ with uniformly bounded derivatives: $\sup_{y\in\mathbb{R}}(|g_h'(y)| + |g_h''(y)| + |g_h'''(y)|) < R$ for some constant $R$.

If Conjectures \ref{C:1.1}--\ref{C:1.3} are true, then that accounts for all quadratic series in Table~\ref{T:1.1} except for $N=15$. 
\begin{enumerate}
\item Is it related to Ramanujan's series $N=15$ in Table~\ref{T:4.1}?
\item Is it related to the level~5 series $N=3$ in~Table~\ref{T:5.1}? {\color{blue}{True by Theorem~\ref{Th:5.1.2}}}.
\end{enumerate}

\label{conj}
Let $s$ be a positive integer. Then:
\begin{enumerate}

\item[(a)] $\prod\limits_{j=1}^{2s} \left( 1 + \frac{2s+1}{k-j} \right) \leq 2$, for $k\geq \frac{(2s+0.5)^2}{\ln(2)} $. 

\item[(b)] $\prod\limits_{j=1}^{2s+1} \left( 1 + \frac{2s+2}{k-j} \right) \leq 2$, for $k \geq \frac{(2s+1.5)^2}{\ln(2)}$. 

\item[(c)] $\prod\limits_{j=0}^{2s-1} \left( 1 + \frac{2s}{k-j} \right) \leq 2$, for $k \geq \frac{4s^2}{\ln(2)}$.

\item[(d)] $\prod\limits_{j=2}^{2s+1} \left( 1 + \frac{2s+2}{k-j} \right) \leq 2$, for $k \geq \frac{(2s+1)^2}{\ln(2)}$.

\end{enumerate}
